using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests;

public class NotificationServiceTests : IDisposable
{
    private readonly NotificationService _service;

    public NotificationServiceTests()
    {
        _service = new NotificationService();
        // Drain any pre-existing notifications from the static queue
        while (_service.ReceiveNotification() != null) { }
    }

    public void Dispose()
    {
        // Drain queue to avoid polluting other tests
        while (_service.ReceiveNotification() != null) { }
        _service.Dispose();
    }

    [Fact]
    public void SendNotification_WithBasicParameters_EnqueuesNotification()
    {
        // Arrange & Act
        _service.SendNotification("Student", "1", EntityOperation.CREATE, "TestUser");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("1", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Equal("TestUser", notification.CreatedBy);
        Assert.False(notification.IsRead);
    }

    [Fact]
    public void SendNotification_WithDisplayName_EnqueuesNotificationWithFormattedMessage()
    {
        // Arrange & Act
        _service.SendNotification("Course", "101", "Mathematics", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Course", notification.EntityType);
        Assert.Equal("101", notification.EntityId);
        Assert.Contains("Mathematics", notification.Message);
        Assert.Equal("Admin", notification.CreatedBy);
    }

    [Fact]
    public void SendNotification_WithNullUserName_DefaultsToSystem()
    {
        // Arrange & Act
        _service.SendNotification("Student", "5", EntityOperation.UPDATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("System", notification.CreatedBy);
    }

    [Fact]
    public void SendNotification_SetsCreatedAtToCurrentTime()
    {
        // Arrange
        var before = DateTime.Now.AddSeconds(-1);

        // Act
        _service.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.True(notification.CreatedAt >= before);
        Assert.True(notification.CreatedAt <= DateTime.Now.AddSeconds(1));
    }

    [Fact]
    public void ReceiveNotification_WhenQueueEmpty_ReturnsNull()
    {
        // Act
        var result = _service.ReceiveNotification();

        // Assert
        Assert.Null(result);
    }

    [Fact]
    public void ReceiveNotification_ReturnsNotificationsInFifoOrder()
    {
        // Arrange
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        _service.SendNotification("Course", "2", EntityOperation.UPDATE);
        _service.SendNotification("Department", "3", EntityOperation.DELETE);

        // Act & Assert
        var first = _service.ReceiveNotification();
        Assert.Equal("Student", first.EntityType);
        Assert.Equal("1", first.EntityId);

        var second = _service.ReceiveNotification();
        Assert.Equal("Course", second.EntityType);
        Assert.Equal("2", second.EntityId);

        var third = _service.ReceiveNotification();
        Assert.Equal("Department", third.EntityType);
        Assert.Equal("3", third.EntityId);

        Assert.Null(_service.ReceiveNotification());
    }

    [Fact]
    public void SendNotification_CreateOperation_GeneratesCorrectMessage()
    {
        // Act
        _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.Equal("New Student 'John Doe' has been created", notification.Message);
    }

    [Fact]
    public void SendNotification_UpdateOperation_GeneratesCorrectMessage()
    {
        // Act
        _service.SendNotification("Course", "101", "Math 101", EntityOperation.UPDATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.Equal("Course 'Math 101' has been updated", notification.Message);
    }

    [Fact]
    public void SendNotification_DeleteOperation_GeneratesCorrectMessage()
    {
        // Act
        _service.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.Equal("Department 'Engineering' has been deleted", notification.Message);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        // Act
        _service.SendNotification("Student", "42", EntityOperation.CREATE);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.Equal("New Student (ID: 42) has been created", notification.Message);
    }

    [Fact]
    public void SendNotification_QueueOverflow_EnforcesMaxLength()
    {
        // Arrange - fill beyond max (500)
        for (int i = 0; i < 510; i++)
        {
            _service.SendNotification("Test", i.ToString(), EntityOperation.CREATE);
        }

        // Act - count remaining items
        int count = 0;
        while (_service.ReceiveNotification() != null)
        {
            count++;
        }

        // Assert - should be at most 500
        Assert.True(count <= 500, $"Queue should not exceed 500 items, but had {count}");
    }

    [Fact]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act & Assert - should not throw
        var exception = Record.Exception(() => _service.MarkAsRead(1));
        Assert.Null(exception);
    }

    [Fact]
    public void MarkAsRead_WithAnyId_DoesNotThrow()
    {
        // Act & Assert
        var exception = Record.Exception(() => _service.MarkAsRead(999));
        Assert.Null(exception);
    }

    [Fact]
    public void Dispose_DoesNotThrow()
    {
        // Act & Assert
        var service = new NotificationService();
        var exception = Record.Exception(() => service.Dispose());
        Assert.Null(exception);
    }
}

namespace ContosoUniversity.Tests;

public class PaginatedListTests
{
    [Fact]
    public void Create_WithItems_ReturnsCorrectPage()
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.Equal(10, result.Count);
        Assert.Equal(1, result.PageIndex);
        Assert.Equal(5, result.TotalPages);
        Assert.Equal(1, result[0]);
        Assert.Equal(10, result[9]);
    }

    [Fact]
    public void Create_SecondPage_ReturnsCorrectItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 10);

        // Assert
        Assert.Equal(10, result.Count);
        Assert.Equal(2, result.PageIndex);
        Assert.Equal(11, result[0]);
        Assert.Equal(20, result[9]);
    }

    [Fact]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 25).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 3, 10);

        // Assert
        Assert.Equal(5, result.Count);
        Assert.Equal(3, result.PageIndex);
        Assert.Equal(3, result.TotalPages);
        Assert.Equal(21, result[0]);
        Assert.Equal(25, result[4]);
    }

    [Fact]
    public void HasPreviousPage_OnFirstPage_ReturnsFalse()
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.False(result.HasPreviousPage);
    }

    [Fact]
    public void HasPreviousPage_OnSecondPage_ReturnsTrue()
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 10);

        // Assert
        Assert.True(result.HasPreviousPage);
    }

    [Fact]
    public void HasNextPage_OnFirstPage_ReturnsTrue()
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.True(result.HasNextPage);
    }

    [Fact]
    public void HasNextPage_OnLastPage_ReturnsFalse()
    {
        // Arrange
        var source = Enumerable.Range(1, 50).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 5, 10);

        // Assert
        Assert.False(result.HasNextPage);
    }

    [Fact]
    public void TotalPages_CalculatedCorrectly_WithExactDivision()
    {
        // Arrange
        var source = Enumerable.Range(1, 30).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.Equal(3, result.TotalPages);
    }

    [Fact]
    public void TotalPages_CalculatedCorrectly_WithRemainder()
    {
        // Arrange
        var source = Enumerable.Range(1, 31).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.Equal(4, result.TotalPages);
    }

    [Fact]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        // Arrange
        var source = Enumerable.Empty<int>().AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.Empty(result);
        Assert.Equal(0, result.TotalPages);
        Assert.Equal(1, result.PageIndex);
    }

    [Fact]
    public void Create_SingleItem_SinglePage()
    {
        // Arrange
        var source = new[] { 42 }.AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.Single(result);
        Assert.Equal(42, result[0]);
        Assert.Equal(1, result.TotalPages);
        Assert.False(result.HasPreviousPage);
        Assert.False(result.HasNextPage);
    }
}

