using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests;

public class StudentsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly StudentsController _controller;

    public StudentsControllerTests()
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: $"StudentsTest_{Guid.NewGuid()}")
            .Options;

        _context = new SchoolContext(options);
        _controller = new StudentsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private void SeedStudents()
    {
        _context.Students.AddRange(
            new Student { ID = 1, LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = new DateTime(2020, 9, 1) },
            new Student { ID = 2, LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = new DateTime(2021, 9, 1) },
            new Student { ID = 3, LastName = "Barzdukas", FirstMidName = "Gytis", EnrollmentDate = new DateTime(2020, 9, 1) },
            new Student { ID = 4, LastName = "Norman", FirstMidName = "Nino", EnrollmentDate = new DateTime(2022, 1, 15) },
            new Student { ID = 5, LastName = "Olivetto", FirstMidName = "Ann", EnrollmentDate = new DateTime(2019, 9, 1) }
        );
        _context.SaveChanges();
    }

    // === Index Tests ===

    [Fact]
    public void Index_NoParameters_ReturnsViewWithStudentsSortedByLastName()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index(null, null, null, null) as ViewResult;

        // Assert
        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal(5, model.Count);
        // Default sort is by LastName ascending
        Assert.Equal("Alexander", model[0].LastName);
        Assert.Equal("Alonso", model[1].LastName);
        Assert.Equal("Barzdukas", model[2].LastName);
    }

    [Fact]
    public void Index_NameDescSort_ReturnsStudentsInDescendingOrder()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index("name_desc", null, null, null) as ViewResult;

        // Assert
        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal("Olivetto", model[0].LastName);
        Assert.Equal("Norman", model[1].LastName);
    }

    [Fact]
    public void Index_DateSort_ReturnsStudentsSortedByDateAscending()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index("Date", null, null, null) as ViewResult;

        // Assert
        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        // Earliest date first
        Assert.Equal("Olivetto", model[0].LastName); // 2019
        Assert.Equal("Alexander", model[1].LastName); // 2020
    }

    [Fact]
    public void Index_DateDescSort_ReturnsStudentsSortedByDateDescending()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index("date_desc", null, null, null) as ViewResult;

        // Assert
        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        // Latest date first
        Assert.Equal("Norman", model[0].LastName); // 2022
        Assert.Equal("Alonso", model[1].LastName); // 2021
    }

    [Fact]
    public void Index_WithSearchString_FiltersStudentsByLastName()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index(null, null, "Al", null) as ViewResult;

        // Assert
        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal(2, model.Count);
        Assert.All(model, s => Assert.Contains("Al", s.LastName + s.FirstMidName));
    }

    [Fact]
    public void Index_WithSearchString_FiltersStudentsByFirstName()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index(null, null, "Carson", null) as ViewResult;

        // Assert
        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Single(model);
        Assert.Equal("Alexander", model[0].LastName);
    }

    [Fact]
    public void Index_WithPage_ReturnsPaginatedResults()
    {
        // Arrange - Add more than 10 students for pagination
        for (int i = 1; i <= 15; i++)
        {
            _context.Students.Add(new Student
            {
                ID = i,
                LastName = $"Student{i:D2}",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2020, 1, 1)
            });
        }
        _context.SaveChanges();

        // Act
        var result = _controller.Index(null, null, null, 2) as ViewResult;

        // Assert
        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal(5, model.Count); // 15 total, page size 10, page 2 = 5
        Assert.Equal(2, model.PageIndex);
    }

    [Fact]
    public void Index_SetsViewBagProperties()
    {
        // Arrange
        SeedStudents();

        // Act
        var result = _controller.Index("Date", null, "test", null) as ViewResult;

        // Assert
        Assert.NotNull(result);
        Assert.Equal("Date", _controller.ViewBag.CurrentSort);
        Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
        Assert.Equal("", _controller.ViewBag.NameSortParm);
        Assert.Equal("test", _controller.ViewBag.CurrentFilter);
    }

    [Fact]
    public void Index_NewSearchString_ResetsPageTo1()
    {
        // Arrange
        SeedStudents();

        // Act - when searchString is not null, page is set to 1
        var result = _controller.Index(null, "OldFilter", "NewSearch", 3) as ViewResult;

        // Assert
        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal(1, model.PageIndex);
    }

    // === Details Tests ===

    [Fact]
    public void Details_ValidId_ReturnsViewWithStudent()
    {
        // Arrange
        var student = new Student { ID = 1, LastName = "Test", FirstMidName = "Student", EnrollmentDate = DateTime.Today };
        _context.Students.Add(student);
        _context.SaveChanges();

        // Act
        var result = _controller.Details(1) as ViewResult;

