namespace ContosoUniversity.Tests;

public class NotificationsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly NotificationsController _controller;

    public NotificationsControllerTests()
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: $"NotificationsTest_{Guid.NewGuid()}")
            .Options;

        _context = new SchoolContext(options);
        _controller = new NotificationsController(_context);

        // Drain any pre-existing notifications from the static queue
        var service = new NotificationService();
        while (service.ReceiveNotification() != null) { }
    }

    public void Dispose()
    {
        // Drain queue to avoid polluting other tests
        var service = new NotificationService();
        while (service.ReceiveNotification() != null) { }
        _controller.Dispose();
        _context.Dispose();
    }

    [Fact]
    public void GetNotifications_WhenQueueEmpty_ReturnsEmptyList()
    {
        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.NotNull(result);
        var jsonData = result.Value;
        Assert.NotNull(jsonData);

        // Use dynamic to inspect JSON result
        var type = jsonData.GetType();
        var successProp = type.GetProperty("success");
        var countProp = type.GetProperty("count");
        Assert.True((bool)successProp.GetValue(jsonData));
        Assert.Equal(0, (int)countProp.GetValue(jsonData));
    }

    [Fact]
    public void GetNotifications_WithNotifications_ReturnsNotifications()
    {
        // Arrange - Send notifications via the service (which uses a static queue)
        var service = new NotificationService();
        service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);
        service.SendNotification("Course", "101", "Math", EntityOperation.UPDATE);

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.NotNull(result);
        var jsonData = result.Value;
        var type = jsonData.GetType();
        var successProp = type.GetProperty("success");
        var countProp = type.GetProperty("count");
        var notificationsProp = type.GetProperty("notifications");

        Assert.True((bool)successProp.GetValue(jsonData));
        Assert.Equal(2, (int)countProp.GetValue(jsonData));

        var notifications = notificationsProp.GetValue(jsonData) as List<Notification>;
        Assert.NotNull(notifications);
        Assert.Equal(2, notifications.Count);
    }

    [Fact]
    public void GetNotifications_LimitsTo10()
    {
        // Arrange - Send more than 10 notifications
        var service = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            service.SendNotification("Student", i.ToString(), EntityOperation.CREATE);
        }

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.NotNull(result);
        var jsonData = result.Value;
        var type = jsonData.GetType();
        var countProp = type.GetProperty("count");
        Assert.Equal(10, (int)countProp.GetValue(jsonData));
    }

    [Fact]
    public void MarkAsRead_ReturnsSuccessJson()
    {
        // Act
        var result = _controller.MarkAsRead(1);

        // Assert
        Assert.NotNull(result);
        var jsonData = result.Value;
        var type = jsonData.GetType();
        var successProp = type.GetProperty("success");
        Assert.True((bool)successProp.GetValue(jsonData));
    }

